@callback(Output("fich-sell-card","children"), Output("fich-sell-hint","children"),
          Input("fich-sell-player","value"))
def _fich_sell_card(player_name):
    if not player_name:
        return html.Div(), html.Div()
    stats = _get_player_stats(player_name)
    role  = _get_role_info(player_name)
    mv, mins, age = stats["mv"], stats["minutes"], stats["age"]
    hint = html.Span(
        f"Valor TM estimado: {_fmt(mv)}  \xb7  Edad: {age}  \xb7  Minutos: {mins}",
        style={"fontSize":"10px","color":"#9CA3AF","fontStyle":"italic"}
    ) if mv else html.Div()

    pos_badges = []
    if role["lat_label"]:
        pos_badges.append(html.Span(role["lat_label"], style={
            "fontSize":"10px","fontWeight":"700","padding":"2px 8px","borderRadius":"99px",
            "background":"#111827","color":"#fff","marginRight":"5px"}))
    if role["role_label"]:
        pos_badges.append(html.Span(role["role_label"], style={
            "fontSize":"10px","padding":"2px 8px","borderRadius":"99px",
            "background":"#FEE2E2","color":"#991B1B","marginRight":"5px"}))

    warning = html.Div([
        html.I(className="ti ti-alert-triangle",
               style={"color":"#D97706","fontSize":"12px","marginRight":"5px"}),
        html.Span("Al vender a ", style={"fontSize":"11px","color":"#92400E"}),
        html.Span(player_name, style={"fontSize":"11px","fontWeight":"700","color":"#92400E"}),
        html.Span(" el Rayo pierde:", style={"fontSize":"11px","color":"#92400E"}),
        html.Div(pos_badges, style={"marginTop":"5px","display":"flex","flexWrap":"wrap","gap":"3px"}),
    ], style={"background":"#FFFBEB","border":"1px solid #FDE68A","borderRadius":"7px",
              "padding":"8px 10px","marginTop":"8px"}) if pos_badges else html.Div()

    card = html.Div([
        html.Div([
            html.Span(player_name, style={"fontSize":"12px","fontWeight":"700","color":"#1A1A2E","marginRight":"8px"}),
            html.Span(stats.get("position") or "?",
                      style={"fontSize":"9px","fontWeight":"700","padding":"1px 6px","borderRadius":"99px",
                             "background":"#F3F4F6","color":"#374151"}),
        ], style={"display":"flex","alignItems":"center"}),
        warning,
    ], style={"background":"#F9FAFB","border":"1px solid #E5E7EB","borderRadius":"7px","padding":"8px 10px"})
    return card, hint
